use std::process::ExitCode;

use holobridge_auth::test_keys::create_test_jwt;
use holobridge_transport::{TransportClientConfig, TransportSmokeClient};
use tracing::{error, info};
use tracing_subscriber::EnvFilter;

#[tokio::main]
async fn main() -> ExitCode {
    init_tracing();

    // Read the existing test private key (generated by test_keygen).
    let priv_key_path = std::env::var("HOLOBRIDGE_AUTH_TEST_PRIVATE_KEY")
        .unwrap_or_else(|_| "/tmp/holobridge_test_priv.pem".to_owned());

    let private_pem = match std::fs::read(&priv_key_path) {
        Ok(data) => data,
        Err(e) => {
            error!(error = %e, path = %priv_key_path, "failed to read test private key — run `cargo run --bin test_keygen` first");
            return ExitCode::FAILURE;
        }
    };
    info!(path = %priv_key_path, "loaded test private key");

    let bundle_id = std::env::var("HOLOBRIDGE_AUTH_BUNDLE_ID")
        .unwrap_or_else(|_| "cloud.hr5.HoloBridge".to_owned());

    // Scenario 1: Valid token
    info!("=== Scenario 1: Valid token ===");
    let valid_token = create_test_jwt(&private_pem, "test-user-001", &bundle_id, false);

    let mut config = TransportClientConfig::from_env();
    config.identity_token = Some(valid_token);
    config.send_goodbye_after_ack = true;

    let client = TransportSmokeClient::new(config);
    let summary = client.runtime_summary();
    info!(endpoint = %summary.remote_endpoint, alpn = %summary.alpn, "auth smoke client connecting (valid token)");

    match client.run().await {
        Ok(()) => info!("scenario 1 (valid token): PASSED"),
        Err(error) => {
            error!(error = %error, "scenario 1 (valid token): FAILED");
            return ExitCode::FAILURE;
        }
    }

    info!("auth smoke test complete");
    ExitCode::SUCCESS
}

fn init_tracing() {
    let filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info"));
    let _ = tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_target(false)
        .try_init();
}
